mapper.update:
UPDATE product_inventory
total_quantity = #{totalQuantity}, available_quantity = #{availableQuantity}, locked_quantity = #{lockedQuantity}, sold_quantity = #{soldQuantity}, warning_quantity = #{warningQuantity}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE product_inventory 
SET available_quantity = available_quantity - #{quantity}, 
    locked_quantity = locked_quantity + #{quantity}, 
    version = version + 1, 
    update_time = CURRENT_TIMESTAMP
WHERE product_id = #{productId} 
AND available_quantity >= #{quantity} 
AND version = #{version}
